import React, { createContext, useState, useEffect } from 'react';

export const AppContext = createContext();

export const AppProvider = ({ children }) => {
  const [user, setUser] = useState(null);       // Текущий пользователь
  const [products, setProducts] = useState([]); // Список товаров
  const [orders, setOrders] = useState([]);     // Заказы пользователя

  // 1. Загрузка товаров (Read)
  const fetchProducts = async () => {
    try {
      const res = await fetch('http://localhost:3001/products');
      const data = await res.json();
      setProducts(data);
    } catch (err) {
      console.error("Ошибка загрузки товаров:", err);
    }
  };

  // 2. Загрузка заказов конкретного юзера (Relationship 1:N)
  const fetchOrders = async () => {
    if (!user) return;
    try {
      const res = await fetch(`http://localhost:3001/orders?userId=${user.id}`);
      const data = await res.json();
      setOrders(data);
    } catch (err) {
      console.error("Ошибка загрузки заказов:", err);
    }
  };

  // 3. Создание заказа (Create)
  const createOrder = async (items) => {
    if (!user) return alert("Войдите в систему!");
    const newOrder = {
      userId: user.id,
      items: items,
      date: new Date().toLocaleString(),
      total: items.reduce((sum, item) => sum + item.price, 0)
    };
    await fetch('http://localhost:3001/orders', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newOrder)
    });
    fetchOrders();
    alert("Заказ оформлен!");
  };

  // 4. Удаление заказа (Delete)
  const deleteOrder = async (id) => {
    await fetch(`http://localhost:3001/orders/${id}`, { method: 'DELETE' });
    setOrders(prev => prev.filter(o => o.id !== id));
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  return (
    <AppContext.Provider value={{ 
      user, setUser, 
      products, setProducts, 
      orders, fetchOrders, 
      createOrder, deleteOrder 
    }}>
      {children}
    </AppContext.Provider>
  );
};
